mapper.select:
select
    id,
    tenant_id,
    pipeline_definition_id,
    job_code,
    pipeline_type,
    file_id,
    related_job_instance_id,
    current_stage,
    last_success_stage,
    run_status,
    trace_id,
    started_at,
    finished_at,
    created_at,
    updated_at
from batch.pipeline_instance
where tenant_id = #{tenantId}

    and file_id = #{fileId}


    and id = #{pipelineInstanceId}


    and pipeline_type = #{pipelineType}


    and run_status = #{runStatus}


    and trace_id = #{traceId}


    and created_at >= #{fromTime}


    and created_at <= #{toTime}

order by id desc

    limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.pipeline_instance
where tenant_id = #{tenantId}

    and file_id = #{fileId}


    and id = #{pipelineInstanceId}


    and pipeline_type = #{pipelineType}


    and run_status = #{runStatus}


    and trace_id = #{traceId}


    and created_at >= #{fromTime}


    and created_at <= #{toTime}
